    54→/**
    55→ * Visitor interface to inspect OWL Class Restrictions.
    56→ *
    57→ * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
    58→ * for both object properties and data properties. It implements the Visitor pattern via
    59→ * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
    60→ *
    61→ * <h2>Usage</h2>
    62→ * <pre>{@code
    63→ * OWLClass myClass = ...;
    64→ * OWLOntology ontology = ...;
    65→ * OWLClass owlThing = dataFactory.getOWLThing();
    66→ *
    67→ * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing, "", false);
    68→ * myClass.accept(visitor);
    69→ *
    70→ * // Access collected restrictions
    71→ * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
    72→ * Set<String> objectProperties = visitor.getObjectPropertyNames();
    73→ * }</pre>
    74→ *
    75→ * <h2>Constructor Parameters</h2>
    76→ * <ul>
    77→ *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
    78→ *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
    79→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    80→ *   <li><b>propertyName</b>: Initial property name context (typically empty "")</li>
    81→ *   <li><b>range</b>: Whether analyzing ranges (typically false for initial call)</li>
    82→ * </ul>
    83→ *
    84→ * <h2>Visitor Traversal Behavior</h2>
    85→ * <p>The visitor recursively processes class hierarchies:
    86→ * <ul>
    87→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    88→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    89→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    90→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    91→ * </ul>
    92→ *
    93→ * <h2>Thread Safety</h2>
    94→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    95→ * traversal and should not be shared between threads or reused for multiple traversals.
    96→ *
    97→ * @see RestrictionInfo
    98→ * @see PropertyNameResolver
    99→ */
   100→public class SchemaVisitor implements OWLObjectVisitor {
   101→
   102→  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
   103→
   104→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
   105→  private final Set<OWLClass> processedClasses;
   106→  private final OWLClass cls;
   107→  private final OWLOntology onto;
   108→  String propertyName;
   109→  OWLClass owlThing;
   110→  Boolean range;
   111→
