   266→  @Override
   267→  public void visit(OWLDataAllValuesFrom ce) {
   268→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   269→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
