   344→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   345→    for (OWLLiteral value : ce.getValues()) {
   346→      // Values are now accessed via DataOneOf.getEnumValues() in mappers
   347→    }
