   367→  private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
   368→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   369→      propertyName = cleanName(nameResolver.resolve(property));
   370→      objectPropertyNames.add(propertyName);
   371→
   372→      final String propName = propertyName;
   373→      RestrictionInfo.from(ce).ifPresent(info ->
   374→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   375→
   376→      // Detect taxonomy patterns
   377→      detectTaxonomyPattern(propertyName, ce.getFiller());
   378→
   379→      if (ce.getFiller().isOWLClass()) {
   380→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   381→      }
   382→    }
   383→    propertyName = "";
   384→  }
