   386→  private void setBooleanCombinationObjectProperties(OWLClassExpression expression,
   387→      Set<OWLClassExpression> ranges,
   388→      Set<OWLObjectProperty> properties) {
   389→    if (propertyName.isEmpty()) {
   390→      for (OWLObjectProperty property : properties) {
   391→        propertyName = cleanName(nameResolver.resolve(property));
   392→        objectPropertyNames.add(propertyName);
   393→        for (OWLClassExpression range : ranges) {
   394→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   395→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   396→              range.accept(this);
   397→            }
   398→          }
   399→        }
   400→      }
   401→
   402→      for (OWLDataProperty property : expression.getDataPropertiesInSignature()) {
   403→        propertyName = cleanName(nameResolver.resolve(property));
   404→        dataPropertyNames.add(propertyName);
   405→        for (OWLClassExpression range : ranges) {
   406→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   407→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   408→              range.accept(this);
   409→            }
   410→          }
   411→        }
   412→      }
   413→    } else {
   414→      for (OWLClassExpression range : ranges) {
   415→        Set<OWLClass> rangeClasses = range.getClassesInSignature();
   416→        if (rangeClasses.size() != 1) {
   417→          range.accept(this);
   418→        } else if (!range.asOWLClass().equals(owlThing)) {
   419→          // Range is tracked in objectPropertyRanges via visitor methods
   420→        } else {
   421→          logger.fine("Ignoring owl:Thing range " + propertyName);
   422→        }
   423→      }
   424→    }
   425→    propertyName = "";
   426→  }
