   431→    if (propertyName.isEmpty()) {
   432→      for (OWLDataProperty property : properties) {
   433→        propertyName = cleanName(nameResolver.resolve(property));
   434→        dataPropertyNames.add(propertyName);
   435→        for (OWLDataRange range : ranges) {
   436→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   437→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   438→              range.accept(this);
   439→            }
   440→          }
   441→        }
   442→      }
   443→
   444→      for (OWLObjectProperty property : expression.getObjectPropertiesInSignature()) {
   445→        propertyName = cleanName(nameResolver.resolve(property));
   446→        objectPropertyNames.add(propertyName);
   447→        for (OWLDataRange range : ranges) {
   448→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   449→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   450→              range.accept(this);
   451→            }
   452→          }
   453→        }
   454→      }
   455→    } else {
   456→      for (OWLDataRange range : ranges) {
   457→        Set<OWLDatatype> rangeDatatypes = range.getDatatypesInSignature();
   458→        if (rangeDatatypes.size() != 1) {
   459→          range.accept(this);
   460→        } else if (!range.asOWLDatatype().asOWLClass().equals(owlThing)) {
   461→          // Range is tracked in dataPropertyRanges via visitor methods
   462→        } else {
   463→          logger.fine("Ignoring owl:Thing range " + propertyName);
   464→        }
   465→      }
