   470→  private void setDataPropertiesWithCardinality(OWLDataCardinalityRestriction ce) {
   471→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   472→      propertyName = cleanName(nameResolver.resolve(property));
   473→      dataPropertyNames.add(propertyName);
   474→
   475→      final String propName = propertyName;
   476→      RestrictionInfo.from(ce).ifPresent(info ->
   477→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   478→
   479→      for (OWLDatatype datatype : ce.getDatatypesInSignature()) {
   480→        dataPropertyRanges.put(propertyName, datatype);
   481→      }
   482→    }
   483→    propertyName = "";
   484→  }
