   519→  /**
   520→   * Detects if a filler class expression represents a taxonomy pattern.
   521→   * Called when processing SomeValuesFrom, AllValuesFrom, or qualified cardinality restrictions.
   522→   */
   523→  private void detectTaxonomyPattern(String propName, OWLClassExpression filler) {
   524→    if (filler instanceof OWLObjectOneOf oneOf) {
   525→      // Pattern A or B: blank node with owl:oneOf
   526→      List<OWLNamedIndividual> individuals = oneOf.individuals()
   527→          .filter(ind -> ind instanceof OWLNamedIndividual)
   528→          .map(ind -> (OWLNamedIndividual) ind)
   529→          .toList();
   530→
   531→      if (!individuals.isEmpty()) {
   532→        boolean hasTypedIndividuals = individuals.stream()
   533→            .anyMatch(ind -> hasDomainClass(ind));
   534→
   535→        if (hasTypedIndividuals) {
   536→          // Pattern B: typed individuals with metadata and property graphs
   537→          Map<String, TaxonomyInfo.IndividualMetadata> metadata = new HashMap<>();
   538→          List<TaxonomyInfo.IndividualGraph> individualGraphs = new ArrayList<>();
   539→
   540→          for (OWLNamedIndividual ind : individuals) {
   541→            OWLClass domainClass = getDomainClass(ind);
   542→            String codeValue = getAnnotationValue(ind, OntologyConstants.SKOS_NOTATION);
   543→            String displayName = getAnnotationValue(ind, OntologyConstants.SKOS_PREFLABEL);
   544→            String definition = getAnnotationValue(ind, OntologyConstants.SKOS_DEFINITION);
   545→            String indName = nameResolver.resolve(ind);
   546→            metadata.put(indName, new TaxonomyInfo.IndividualMetadata(
   547→                codeValue, displayName, definition, domainClass));
   548→
   549→            // Extract individual graph with property assertions
   550→            TaxonomyInfo.IndividualGraph graph = extractIndividualGraph(ind);
   551→            individualGraphs.add(graph);
   552→          }
   553→          taxonomyPatterns.put(propName, TaxonomyInfo.patternB(propName, individuals, metadata, individualGraphs));
   554→        } else {
   555→          // Pattern A: untyped individuals (inline enum)
   556→          taxonomyPatterns.put(propName, TaxonomyInfo.patternA(propName, individuals));
   557→        }
   558→      }
   559→    } else if (filler.isNamed() && filler instanceof OWLClass targetClass) {
   560→      // Skip owl:Thing - it doesn't represent a taxonomy pattern
   561→      if (targetClass.isOWLThing()) {
   562→        return;
   563→      }
   564→      // Named class - check for Pattern C or D
   565→      if (isSubClassOfSkosConcept(targetClass) || hasInSchemeRestriction(targetClass)) {
   566→        // Pattern D: SKOS taxonomy
   567→        var conceptScheme = findConceptScheme(targetClass);
   568→        var individuals = findSkosConceptIndividuals(targetClass);
   569→        taxonomyPatterns.put(propName, TaxonomyInfo.patternD(
   570→            propName, targetClass, individuals, conceptScheme));
   571→      } else if (!hasObjectPropertyRestrictions(targetClass)) {
   572→        // Pattern C: class-based taxonomy (no object property restrictions)
   573→        var individuals = findClassIndividuals(targetClass);
   574→        boolean hasHierarchy = hasSubclassHierarchy(targetClass);
   575→        taxonomyPatterns.put(propName, TaxonomyInfo.patternC(
   576→            propName, targetClass, individuals, hasHierarchy));
   577→      }
   578→      // else: domain class with object property restrictions - not a taxonomy
   579→    }
   580→  }
   581→
   582→  private boolean hasDomainClass(OWLNamedIndividual individual) {
   583→    return EntitySearcher.getTypes(individual, onto)
   584→        .anyMatch(type -> type.isNamed() && !type.isOWLThing());
   585→  }
   586→
   587→  private OWLClass getDomainClass(OWLNamedIndividual individual) {
   588→    return EntitySearcher.getTypes(individual, onto)
   589→        .filter(type -> type.isNamed() && !type.isOWLThing())
   590→        .map(OWLClassExpression::asOWLClass)
   591→        .findFirst()
   592→        .orElse(null);
   593→  }
   594→
   595→  private String getAnnotationValue(OWLNamedIndividual individual, org.semanticweb.owlapi.model.IRI annotationIRI) {
   596→    // Match by short form to handle namespace flattening
   597→    String shortForm = annotationIRI.getShortForm();
   598→    return EntitySearcher.getAnnotations(individual, onto)
   599→        .filter(ann -> nameResolver.resolve(ann.getProperty()).equals(shortForm))
   600→        .findFirst()
   601→        .flatMap(ann -> ann.getValue().asLiteral())
   602→        .map(lit -> lit.getLiteral())
   603→        .orElse(null);
   604→  }
   605→
   606→  /**
   607→   * Extracts an IndividualGraph for a Pattern B individual, including all property assertions.
   608→   */
   609→  private TaxonomyInfo.IndividualGraph extractIndividualGraph(OWLNamedIndividual individual) {
   610→    String code = getCodeValue(individual);
   611→    String displayName = getAnnotationValue(individual, OntologyConstants.SKOS_PREFLABEL);
   612→    String definition = getAnnotationValue(individual, OntologyConstants.SKOS_DEFINITION);
   613→
   614→    List<TaxonomyInfo.PropertyAssertion> assertions = new ArrayList<>();
   615→
   616→    // Extract data property assertions from axioms
   617→    onto.dataPropertyAssertionAxioms(individual)
   618→        .forEach(axiom -> {
   619→          if (axiom.getProperty().isNamed()) {
   620→            String propName = nameResolver.resolve(axiom.getProperty().asOWLDataProperty());
   621→            OWLLiteral lit = axiom.getObject();
   622→            assertions.add(new TaxonomyInfo.PropertyAssertion(
   623→                propName,
   624→                lit.getLiteral(),
   625→                lit.getDatatype(),
   626→                null
   627→            ));
   628→          }
   629→        });
   630→
   631→    // Extract object property assertions from axioms
   632→    onto.objectPropertyAssertionAxioms(individual)
   633→        .forEach(axiom -> {
   634→          if (axiom.getProperty().isNamed() && axiom.getObject().isNamed()) {
   635→            String propName = nameResolver.resolve(axiom.getProperty().asOWLObjectProperty());
   636→            assertions.add(new TaxonomyInfo.PropertyAssertion(
   637→                propName,
   638→                null,
   639→                null,
   640→                axiom.getObject().asOWLNamedIndividual()
   641→            ));
   642→          }
   643→        });
   644→
   645→    return new TaxonomyInfo.IndividualGraph(code, displayName, definition, assertions, individual);
   646→  }
   647→
   648→  /**
   649→   * Gets the code value for an individual: skos:notation if present, otherwise IRI local name.
   650→   */
   651→  private String getCodeValue(OWLNamedIndividual individual) {
   652→    String notation = getAnnotationValue(individual, OntologyConstants.SKOS_NOTATION);
   653→    return notation != null ? notation : nameResolver.resolve(individual);
   654→  }
   655→
   656→  private boolean isSubClassOfSkosConcept(OWLClass cls) {
   657→    return EntitySearcher.getSuperClasses(cls, onto)
   658→        .anyMatch(superCls -> superCls.isNamed() &&
   659→            superCls.asOWLClass().getIRI().equals(OntologyConstants.SKOS_CONCEPT));
   660→  }
   661→
   662→  private boolean hasInSchemeRestriction(OWLClass cls) {
   663→    return onto.subClassAxiomsForSubClass(cls)
   664→        .map(ax -> ax.getSuperClass())
   665→        .anyMatch(superCls -> {
   666→          if (superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue hasValue) {
   667→            return hasValue.getProperty().isNamed() &&
   668→                hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME);
   669→          }
   670→          return false;
   671→        });
   672→  }
   673→
   674→  private boolean hasObjectPropertyRestrictions(OWLClass cls) {
   675→    return onto.subClassAxiomsForSubClass(cls)
   676→        .map(ax -> ax.getSuperClass())
   677→        .anyMatch(superCls -> !superCls.getObjectPropertiesInSignature().isEmpty());
   678→  }
   679→
   680→  private boolean hasSubclassHierarchy(OWLClass cls) {
   681→    return onto.classesInSignature()
   682→        .anyMatch(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
   683→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)));
   684→  }
   685→
   686→  private org.semanticweb.owlapi.model.OWLIndividual findConceptScheme(OWLClass cls) {
   687→    // Look for skos:inScheme restriction value
   688→    return onto.subClassAxiomsForSubClass(cls)
   689→        .map(ax -> ax.getSuperClass())
   690→        .filter(superCls -> superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue)
   691→        .map(superCls -> (org.semanticweb.owlapi.model.OWLObjectHasValue) superCls)
   692→        .filter(hasValue -> hasValue.getProperty().isNamed() &&
   693→            hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME))
   694→        .map(hasValue -> hasValue.getFiller())
   695→        .findFirst()
   696→        .orElse(null);
   697→  }
   698→
   699→  private List<OWLNamedIndividual> findSkosConceptIndividuals(OWLClass cls) {
   700→    List<OWLNamedIndividual> result = new ArrayList<>();
   701→    // Find individuals that are instances of this class or have skos:inScheme pointing to the same scheme
   702→    EntitySearcher.getIndividuals(cls, onto)
   703→        .filter(ind -> ind instanceof OWLNamedIndividual)
   704→        .map(ind -> (OWLNamedIndividual) ind)
   705→        .forEach(result::add);
   706→    return result;
   707→  }
   708→
   709→  private List<OWLNamedIndividual> findClassIndividuals(OWLClass cls) {
   710→    List<OWLNamedIndividual> result = new ArrayList<>();
   711→    // Find all individuals of this class and its subclasses
   712→    EntitySearcher.getIndividuals(cls, onto)
   713→        .filter(ind -> ind instanceof OWLNamedIndividual)
   714→        .map(ind -> (OWLNamedIndividual) ind)
   715→        .forEach(result::add);
   716→
   717→    // Also check subclasses
   718→    onto.classesInSignature()
   719→        .filter(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
   720→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)))
   721→        .forEach(subCls -> EntitySearcher.getIndividuals(subCls, onto)
   722→            .filter(ind -> ind instanceof OWLNamedIndividual)
   723→            .map(ind -> (OWLNamedIndividual) ind)
   724→            .forEach(result::add));
   725→
   726→    return result;
   727→  }
   728→}

