package com.grl.component.schema;

import com.google.common.collect.HashMultimap;
import com.google.common.collect.Multimap;
import com.google.common.collect.Multimaps;
import com.grl.component.asg.OntologyConstants;
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.logging.Logger;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLClassExpression;
import org.semanticweb.owlapi.model.OWLDataAllValuesFrom;
import org.semanticweb.owlapi.model.OWLDataCardinalityRestriction;
import org.semanticweb.owlapi.model.OWLDataComplementOf;
import org.semanticweb.owlapi.model.OWLDataExactCardinality;
import org.semanticweb.owlapi.model.OWLDataHasValue;
import org.semanticweb.owlapi.model.OWLDataIntersectionOf;
import org.semanticweb.owlapi.model.OWLDataMaxCardinality;
import org.semanticweb.owlapi.model.OWLDataMinCardinality;
import org.semanticweb.owlapi.model.OWLDataOneOf;
import org.semanticweb.owlapi.model.OWLDataProperty;
import org.semanticweb.owlapi.model.OWLDataRange;
import org.semanticweb.owlapi.model.OWLDataSomeValuesFrom;
import org.semanticweb.owlapi.model.OWLDataUnionOf;
import org.semanticweb.owlapi.model.OWLDatatype;
import org.semanticweb.owlapi.model.OWLLiteral;
import org.semanticweb.owlapi.model.OWLObjectAllValuesFrom;
import org.semanticweb.owlapi.model.OWLObjectCardinalityRestriction;
import org.semanticweb.owlapi.model.OWLObjectComplementOf;
import org.semanticweb.owlapi.model.OWLObjectExactCardinality;
import org.semanticweb.owlapi.model.OWLObjectHasValue;
import org.semanticweb.owlapi.model.OWLObjectIntersectionOf;
import org.semanticweb.owlapi.model.OWLObjectMaxCardinality;
import org.semanticweb.owlapi.model.OWLObjectMinCardinality;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLObjectOneOf;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLObjectSomeValuesFrom;
import org.semanticweb.owlapi.model.OWLDataProperty;
import org.semanticweb.owlapi.model.OWLLiteral;
import org.semanticweb.owlapi.search.EntitySearcher;
import org.semanticweb.owlapi.model.OWLObjectUnionOf;
import org.semanticweb.owlapi.model.OWLObjectVisitor;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLSubClassOfAxiom;

/**
 * Visitor interface to inspect OWL Class Restrictions.
 *
 * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
 * for both object properties and data properties. It implements the Visitor pattern via
 * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
 *
 * <h2>Usage</h2>
 * <pre>{@code
 * OWLClass myClass = ...;
 * OWLOntology ontology = ...;
 * OWLClass owlThing = dataFactory.getOWLThing();
 *
 * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing, "", false);
 * myClass.accept(visitor);
 *
 * // Access collected restrictions
 * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
 * Set<String> objectProperties = visitor.getObjectPropertyNames();
 * }</pre>
 *
 * <h2>Constructor Parameters</h2>
 * <ul>
 *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
 *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
 *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
 *   <li><b>propertyName</b>: Initial property name context (typically empty "")</li>
 *   <li><b>range</b>: Whether analyzing ranges (typically false for initial call)</li>
 * </ul>
 *
 * <h2>Visitor Traversal Behavior</h2>
 * <p>The visitor recursively processes class hierarchies:
 * <ul>
 *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
 *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
 *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
 *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
 * </ul>
 *
 * <h2>Thread Safety</h2>
 * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
 * traversal and should not be shared between threads or reused for multiple traversals.
 *
 * @see RestrictionInfo
 * @see PropertyNameResolver
 */
public class SchemaVisitor implements OWLObjectVisitor {

  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());

  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
  private final Set<OWLClass> processedClasses;
  private final OWLClass cls;
  private final OWLOntology onto;
  String propertyName;
  OWLClass owlThing;
  Boolean range;


  // Type-safe storage (private with unmodifiable getters)
  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();

  // Property name tracking (minimal - just names, not full OWL objects)
  private final Set<String> objectPropertyNames = new HashSet<>();
  private final Set<String> dataPropertyNames = new HashSet<>();

  // Taxonomy pattern tracking
  private final Map<String, TaxonomyInfo> taxonomyPatterns = new HashMap<>();

  /**
   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   *
   * @param visitedClass the OWL class to analyze for restrictions
   * @param onto         the ontology containing the class and its axioms
   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   *                     no information)
   * @param propertyName initial property name context (typically empty "" for top-level analysis)
   * @param range        whether this visitor is analyzing property ranges (typically false for
   *                     initial call)
   */
  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing,
      String propertyName, Boolean range) {
    processedClasses = new HashSet<>();
    this.cls = visitedClass;
    this.onto = onto;
    this.propertyName = propertyName;
    this.owlThing = owlThing;
    this.range = range;
  }

  @Override
  public void visit(OWLClass ce) {
    if (!processedClasses.contains(ce)) {
      processedClasses.add(ce);
      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
        ax.getSuperClass().accept(this);
      }
    }
  }

  @Override
  public void visit(OWLObjectSomeValuesFrom ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      objectPropertyNames.add(propertyName);
      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
          .add(new RestrictionInfo.SomeValuesFrom(ce));

      // Detect taxonomy patterns
      detectTaxonomyPattern(propertyName, ce.getFiller());
    }

    if (ce.getFiller() instanceof OWLObjectUnionOf ||
        ce.getFiller() instanceof OWLObjectIntersectionOf ||
        ce.getFiller() instanceof OWLObjectOneOf) {
      ce.getFiller().accept(this);
    } else {
      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
      } else {
        logger.fine("Ignoring owl:Thing range " + propertyName);
      }
    }
    propertyName = "";
  }

  @Override
  public void visit(OWLObjectAllValuesFrom ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      objectPropertyNames.add(propertyName);
      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
          .add(new RestrictionInfo.AllValuesFrom(ce));

      // Detect taxonomy patterns
      detectTaxonomyPattern(propertyName, ce.getFiller());
    }

    if (ce.getFiller() instanceof OWLObjectUnionOf
        || ce.getFiller() instanceof OWLObjectIntersectionOf
        || ce.getFiller() instanceof OWLObjectOneOf) {
      ce.getFiller().accept(this);
    } else {
      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
      } else {
        logger.fine("Ignoring owl:Thing range " + propertyName);
      }
    }
    propertyName = "";
  }

  @Override
  public void visit(OWLObjectUnionOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
        ce.getObjectPropertiesInSignature());
  }

  @Override
  public void visit(OWLObjectIntersectionOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
        ce.getObjectPropertiesInSignature());
  }

  @Override
  public void visit(OWLObjectMinCardinality ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setPropertiesWithCardinality(ce);
  }

  @Override
  public void visit(OWLObjectMaxCardinality ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setPropertiesWithCardinality(ce);
  }

  @Override
  public void visit(OWLObjectExactCardinality ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setPropertiesWithCardinality(ce);
  }

  @Override
  public void visit(OWLObjectComplementOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    if (!propertyName.isEmpty()) {
      ce.getOperand().accept(this);
    }
  }

  @Override
  public void visit(OWLObjectHasValue ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      objectPropertyNames.add(propertyName);
    }
    propertyName = "";
  }

  @Override
  public void visit(OWLObjectOneOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    propertyName = "";
  }

  @Override
  public void visit(OWLDataAllValuesFrom ce) {
    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      dataPropertyNames.add(propertyName);
      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
          .add(new RestrictionInfo.DataAllValuesFrom(ce));
    }

    if (ce.getFiller() instanceof OWLDataUnionOf
        || ce.getFiller() instanceof OWLDataIntersectionOf) {
      ce.getFiller().accept(this);
    } else {
      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
        dataPropertyRanges.put(propertyName, ce.getFiller().asOWLDatatype());
      } else {
        logger.fine("Ignoring owl:Thing range " + propertyName);
      }
    }
    propertyName = "";
  }

  @Override
  public void visit(OWLDataSomeValuesFrom ce) {
    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      dataPropertyNames.add(propertyName);
      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
          .add(new RestrictionInfo.DataSomeValuesFrom(ce));
    }

    if (ce.getFiller() instanceof OWLDataUnionOf
        || ce.getFiller() instanceof OWLDataIntersectionOf) {
      ce.getFiller().accept(this);
    } else {
      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
        dataPropertyRanges.put(propertyName, ce.getFiller().asOWLDatatype());
      } else {
        logger.fine("Ignoring owl:Thing range " + propertyName);
      }
    }
    propertyName = "";
  }

  @Override
  public void visit(OWLDataUnionOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
  }

  @Override
  public void visit(OWLDataIntersectionOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
  }

  @Override
  public void visit(OWLDataMinCardinality ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setDataPropertiesWithCardinality(ce);
  }

  @Override
  public void visit(OWLDataMaxCardinality ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setDataPropertiesWithCardinality(ce);
  }

  @Override
  public void visit(OWLDataExactCardinality ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    setDataPropertiesWithCardinality(ce);
  }

  @Override
  public void visit(OWLDataOneOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    for (OWLLiteral value : ce.getValues()) {
      // Values are now accessed via DataOneOf.getEnumValues() in mappers
    }
    propertyName = "";
  }

  @Override
  public void visit(OWLDataComplementOf ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    propertyName = "";
  }

  @Override
  public void visit(OWLDataHasValue ce) {
    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      dataPropertyNames.add(propertyName);
    }
    propertyName = "";
  }

  private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      objectPropertyNames.add(propertyName);

      final String propName = propertyName;
      RestrictionInfo.from(ce).ifPresent(info ->
          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));

      // Detect taxonomy patterns
      detectTaxonomyPattern(propertyName, ce.getFiller());

      if (ce.getFiller().isOWLClass()) {
        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
      }
    }
    propertyName = "";
  }

  private void setBooleanCombinationObjectProperties(OWLClassExpression expression,
      Set<OWLClassExpression> ranges,
      Set<OWLObjectProperty> properties) {
    if (propertyName.isEmpty()) {
      for (OWLObjectProperty property : properties) {
        propertyName = cleanName(nameResolver.resolve(property));
        objectPropertyNames.add(propertyName);
        for (OWLClassExpression range : ranges) {
          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }

      for (OWLDataProperty property : expression.getDataPropertiesInSignature()) {
        propertyName = cleanName(nameResolver.resolve(property));
        dataPropertyNames.add(propertyName);
        for (OWLClassExpression range : ranges) {
          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }
    } else {
      for (OWLClassExpression range : ranges) {
        Set<OWLClass> rangeClasses = range.getClassesInSignature();
        if (rangeClasses.size() != 1) {
          range.accept(this);
        } else if (!range.asOWLClass().equals(owlThing)) {
          // Range is tracked in objectPropertyRanges via visitor methods
        } else {
          logger.fine("Ignoring owl:Thing range " + propertyName);
        }
      }
    }
    propertyName = "";
  }

  private void setBooleanCombinationDataProperties(OWLDataRange expression,
      Set<OWLDataRange> ranges,
      Set<OWLDataProperty> properties) {
    if (propertyName.isEmpty()) {
      for (OWLDataProperty property : properties) {
        propertyName = cleanName(nameResolver.resolve(property));
        dataPropertyNames.add(propertyName);
        for (OWLDataRange range : ranges) {
          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }

      for (OWLObjectProperty property : expression.getObjectPropertiesInSignature()) {
        propertyName = cleanName(nameResolver.resolve(property));
        objectPropertyNames.add(propertyName);
        for (OWLDataRange range : ranges) {
          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }
    } else {
      for (OWLDataRange range : ranges) {
        Set<OWLDatatype> rangeDatatypes = range.getDatatypesInSignature();
        if (rangeDatatypes.size() != 1) {
          range.accept(this);
        } else if (!range.asOWLDatatype().asOWLClass().equals(owlThing)) {
          // Range is tracked in dataPropertyRanges via visitor methods
        } else {
          logger.fine("Ignoring owl:Thing range " + propertyName);
        }
      }
    }
    propertyName = "";
  }

  private void setDataPropertiesWithCardinality(OWLDataCardinalityRestriction ce) {
    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      dataPropertyNames.add(propertyName);

      final String propName = propertyName;
      RestrictionInfo.from(ce).ifPresent(info ->
          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));

      for (OWLDatatype datatype : ce.getDatatypesInSignature()) {
        dataPropertyRanges.put(propertyName, datatype);
      }
    }
    propertyName = "";
  }

  // Getters for type-safe storage (unmodifiable views)
  public Map<String, Set<RestrictionInfo>> getRestrictions() {
    return Collections.unmodifiableMap(restrictions);
  }

  public Multimap<String, OWLClass> getObjectPropertyRanges() {
    return Multimaps.unmodifiableMultimap(objectPropertyRanges);
  }

  public Multimap<String, OWLDatatype> getDataPropertyRanges() {
    return Multimaps.unmodifiableMultimap(dataPropertyRanges);
  }

  public Set<String> getObjectPropertyNames() {
    return Collections.unmodifiableSet(objectPropertyNames);
  }

  public Set<String> getDataPropertyNames() {
    return Collections.unmodifiableSet(dataPropertyNames);
  }

  public Map<String, TaxonomyInfo> getTaxonomyPatterns() {
    return Collections.unmodifiableMap(taxonomyPatterns);
  }

  public OWLOntology getOntology() {
    return onto;
  }

  private static String cleanName(String propertyName) {
    return Objects.requireNonNull(propertyName);
  }

  /**
   * Detects if a filler class expression represents a taxonomy pattern.
   * Called when processing SomeValuesFrom, AllValuesFrom, or qualified cardinality restrictions.
   */
  private void detectTaxonomyPattern(String propName, OWLClassExpression filler) {
    if (filler instanceof OWLObjectOneOf oneOf) {
      // Pattern A or B: blank node with owl:oneOf
      List<OWLNamedIndividual> individuals = oneOf.individuals()
          .filter(ind -> ind instanceof OWLNamedIndividual)
          .map(ind -> (OWLNamedIndividual) ind)
          .toList();

      if (!individuals.isEmpty()) {
        boolean hasTypedIndividuals = individuals.stream()
            .anyMatch(ind -> hasDomainClass(ind));

        if (hasTypedIndividuals) {
          // Pattern B: typed individuals with metadata and property graphs
          Map<String, TaxonomyInfo.IndividualMetadata> metadata = new HashMap<>();
          List<TaxonomyInfo.IndividualGraph> individualGraphs = new ArrayList<>();

          for (OWLNamedIndividual ind : individuals) {
            OWLClass domainClass = getDomainClass(ind);
            String codeValue = getAnnotationValue(ind, OntologyConstants.SKOS_NOTATION);
            String displayName = getAnnotationValue(ind, OntologyConstants.SKOS_PREFLABEL);
            String definition = getAnnotationValue(ind, OntologyConstants.SKOS_DEFINITION);
            String indName = nameResolver.resolve(ind);
            metadata.put(indName, new TaxonomyInfo.IndividualMetadata(
                codeValue, displayName, definition, domainClass));

            // Extract individual graph with property assertions
            TaxonomyInfo.IndividualGraph graph = extractIndividualGraph(ind);
            individualGraphs.add(graph);
          }
          taxonomyPatterns.put(propName, TaxonomyInfo.patternB(propName, individuals, metadata, individualGraphs));
        } else {
          // Pattern A: untyped individuals (inline enum)
          taxonomyPatterns.put(propName, TaxonomyInfo.patternA(propName, individuals));
        }
      }
    } else if (filler.isNamed() && filler instanceof OWLClass targetClass) {
      // Skip owl:Thing - it doesn't represent a taxonomy pattern
      if (targetClass.isOWLThing()) {
        return;
      }
      // Named class - check for Pattern C or D
      if (isSubClassOfSkosConcept(targetClass) || hasInSchemeRestriction(targetClass)) {
        // Pattern D: SKOS taxonomy
        var conceptScheme = findConceptScheme(targetClass);
        var individuals = findSkosConceptIndividuals(targetClass);
        taxonomyPatterns.put(propName, TaxonomyInfo.patternD(
            propName, targetClass, individuals, conceptScheme));
      } else if (!hasObjectPropertyRestrictions(targetClass)) {
        // Pattern C: class-based taxonomy (no object property restrictions)
        var individuals = findClassIndividuals(targetClass);
        boolean hasHierarchy = hasSubclassHierarchy(targetClass);
        taxonomyPatterns.put(propName, TaxonomyInfo.patternC(
            propName, targetClass, individuals, hasHierarchy));
      }
      // else: domain class with object property restrictions - not a taxonomy
    }
  }

  private boolean hasDomainClass(OWLNamedIndividual individual) {
    return EntitySearcher.getTypes(individual, onto)
        .anyMatch(type -> type.isNamed() && !type.isOWLThing());
  }

  private OWLClass getDomainClass(OWLNamedIndividual individual) {
    return EntitySearcher.getTypes(individual, onto)
        .filter(type -> type.isNamed() && !type.isOWLThing())
        .map(OWLClassExpression::asOWLClass)
        .findFirst()
        .orElse(null);
  }

  private String getAnnotationValue(OWLNamedIndividual individual, org.semanticweb.owlapi.model.IRI annotationIRI) {
    // Match by short form to handle namespace flattening
    String shortForm = annotationIRI.getShortForm();
    return EntitySearcher.getAnnotations(individual, onto)
        .filter(ann -> nameResolver.resolve(ann.getProperty()).equals(shortForm))
        .findFirst()
        .flatMap(ann -> ann.getValue().asLiteral())
        .map(lit -> lit.getLiteral())
        .orElse(null);
  }

  /**
   * Extracts an IndividualGraph for a Pattern B individual, including all property assertions.
   */
  private TaxonomyInfo.IndividualGraph extractIndividualGraph(OWLNamedIndividual individual) {
    String code = getCodeValue(individual);
    String displayName = getAnnotationValue(individual, OntologyConstants.SKOS_PREFLABEL);
    String definition = getAnnotationValue(individual, OntologyConstants.SKOS_DEFINITION);

    List<TaxonomyInfo.PropertyAssertion> assertions = new ArrayList<>();

    // Extract data property assertions from axioms
    onto.dataPropertyAssertionAxioms(individual)
        .forEach(axiom -> {
          if (axiom.getProperty().isNamed()) {
            String propName = nameResolver.resolve(axiom.getProperty().asOWLDataProperty());
            OWLLiteral lit = axiom.getObject();
            assertions.add(new TaxonomyInfo.PropertyAssertion(
                propName,
                lit.getLiteral(),
                lit.getDatatype(),
                null
            ));
          }
        });

    // Extract object property assertions from axioms
    onto.objectPropertyAssertionAxioms(individual)
        .forEach(axiom -> {
          if (axiom.getProperty().isNamed() && axiom.getObject().isNamed()) {
            String propName = nameResolver.resolve(axiom.getProperty().asOWLObjectProperty());
            assertions.add(new TaxonomyInfo.PropertyAssertion(
                propName,
                null,
                null,
                axiom.getObject().asOWLNamedIndividual()
            ));
          }
        });

    return new TaxonomyInfo.IndividualGraph(code, displayName, definition, assertions, individual);
  }

  /**
   * Gets the code value for an individual: skos:notation if present, otherwise IRI local name.
   */
  private String getCodeValue(OWLNamedIndividual individual) {
    String notation = getAnnotationValue(individual, OntologyConstants.SKOS_NOTATION);
    return notation != null ? notation : nameResolver.resolve(individual);
  }

  private boolean isSubClassOfSkosConcept(OWLClass cls) {
    return EntitySearcher.getSuperClasses(cls, onto)
        .anyMatch(superCls -> superCls.isNamed() &&
            superCls.asOWLClass().getIRI().equals(OntologyConstants.SKOS_CONCEPT));
  }

  private boolean hasInSchemeRestriction(OWLClass cls) {
    return onto.subClassAxiomsForSubClass(cls)
        .map(ax -> ax.getSuperClass())
        .anyMatch(superCls -> {
          if (superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue hasValue) {
            return hasValue.getProperty().isNamed() &&
                hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME);
          }
          return false;
        });
  }

  private boolean hasObjectPropertyRestrictions(OWLClass cls) {
    return onto.subClassAxiomsForSubClass(cls)
        .map(ax -> ax.getSuperClass())
        .anyMatch(superCls -> !superCls.getObjectPropertiesInSignature().isEmpty());
  }

  private boolean hasSubclassHierarchy(OWLClass cls) {
    return onto.classesInSignature()
        .anyMatch(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)));
  }

  private org.semanticweb.owlapi.model.OWLIndividual findConceptScheme(OWLClass cls) {
    // Look for skos:inScheme restriction value
    return onto.subClassAxiomsForSubClass(cls)
        .map(ax -> ax.getSuperClass())
        .filter(superCls -> superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue)
        .map(superCls -> (org.semanticweb.owlapi.model.OWLObjectHasValue) superCls)
        .filter(hasValue -> hasValue.getProperty().isNamed() &&
            hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME))
        .map(hasValue -> hasValue.getFiller())
        .findFirst()
        .orElse(null);
  }

  private List<OWLNamedIndividual> findSkosConceptIndividuals(OWLClass cls) {
    List<OWLNamedIndividual> result = new ArrayList<>();
    // Find individuals that are instances of this class or have skos:inScheme pointing to the same scheme
    EntitySearcher.getIndividuals(cls, onto)
        .filter(ind -> ind instanceof OWLNamedIndividual)
        .map(ind -> (OWLNamedIndividual) ind)
        .forEach(result::add);
    return result;
  }

  private List<OWLNamedIndividual> findClassIndividuals(OWLClass cls) {
    List<OWLNamedIndividual> result = new ArrayList<>();
    // Find all individuals of this class and its subclasses
    EntitySearcher.getIndividuals(cls, onto)
        .filter(ind -> ind instanceof OWLNamedIndividual)
        .map(ind -> (OWLNamedIndividual) ind)
        .forEach(result::add);

    // Also check subclasses
    onto.classesInSignature()
        .filter(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)))
        .forEach(subCls -> EntitySearcher.getIndividuals(subCls, onto)
            .filter(ind -> ind instanceof OWLNamedIndividual)
            .map(ind -> (OWLNamedIndividual) ind)
            .forEach(result::add));

    return result;
  }
}

package com.grl.component.schema;

import java.util.List;
import java.util.Map;
import java.util.Optional;
import javax.annotation.Nullable;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLIndividual;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLDatatype;

/**
 * Holds detected taxonomy information for a property restriction.
 *
 * <p>This record captures all the information needed to generate OpenAPI schemas
 * for different taxonomy patterns (A, B, C, D).
 *
 * @param pattern the detected taxonomy pattern
 * @param individuals list of named individuals (for patterns A/B with owl:oneOf)
 * @param targetClass the target class for class-based taxonomies (patterns C/D)
 * @param hasHierarchy whether the taxonomy has a class hierarchy (pattern C)
 * @param conceptScheme the SKOS ConceptScheme individual (pattern D)
 * @param propertyName the property name this taxonomy is associated with
 * @param metadata individual metadata keyed by individual IRI short name (for pattern B)
 * @param individualGraphs list of individual graphs with property assertions (for pattern B)
 * @see TaxonomyPattern
 */
public record TaxonomyInfo(
    TaxonomyPattern pattern,
    List<OWLNamedIndividual> individuals,
    @Nullable OWLClass targetClass,
    boolean hasHierarchy,
    @Nullable OWLIndividual conceptScheme,
    String propertyName,
    Map<String, IndividualMetadata> metadata,
    List<IndividualGraph> individualGraphs
) {

  /**
   * Metadata for a typed individual (Pattern B).
   *
   * @param codeValue the code value (from codeValue annotation)
   * @param displayName the display name (from displayName annotation)
   * @param definition the definition (from skos:definition annotation)
   * @param domainClass the domain class type of the individual
   */
  public record IndividualMetadata(
      @Nullable String codeValue,
      @Nullable String displayName,
      @Nullable String definition,
      @Nullable OWLClass domainClass
  ) {
    public static IndividualMetadata empty() {
      return new IndividualMetadata(null, null, null, null);
    }
  }

  /**
   * Represents a property assertion on an individual (Pattern B).
   * Either a data property assertion (literalValue set) or object property assertion (objectValue set).
   *
   * @param propertyName the resolved property name
   * @param literalValue the literal value for data properties
   * @param datatype the XSD datatype for data properties
   * @param objectValue the target individual for object properties
   */
  public record PropertyAssertion(
      String propertyName,
      @Nullable String literalValue,
      @Nullable OWLDatatype datatype,
      @Nullable OWLNamedIndividual objectValue
  ) {
    /**
     * @return true if this is a data property assertion
     */
    public boolean isDataProperty() {
      return literalValue != null;
    }

    /**
     * @return true if this is an object property assertion
     */
    public boolean isObjectProperty() {
      return objectValue != null;
    }
  }

  /**
   * Represents an individual with its property assertions (Pattern B).
   * Used for generating oneOf schemas with const objects.
   *
   * @param code the code value (from skos:notation or IRI local name fallback)
   * @param displayName the display name (from skos:prefLabel)
   * @param definition the definition (from skos:definition)
   * @param assertions list of property assertions (data and object properties)
   * @param individual the original OWL individual
   */
  public record IndividualGraph(
      String code,
      @Nullable String displayName,
      @Nullable String definition,
      List<PropertyAssertion> assertions,
      OWLNamedIndividual individual
  ) {}

  /**
   * Creates TaxonomyInfo for Pattern A (inline enum with untyped individuals).
   */
  public static TaxonomyInfo patternA(String propertyName, List<OWLNamedIndividual> individuals) {
    return new TaxonomyInfo(
        TaxonomyPattern.PATTERN_A,
        individuals,
        null,
        false,
        null,
        propertyName,
        Map.of(),
        List.of()
    );
  }

  /**
   * Creates TaxonomyInfo for Pattern B (typed individuals with metadata).
   */
  public static TaxonomyInfo patternB(
      String propertyName,
      List<OWLNamedIndividual> individuals,
      Map<String, IndividualMetadata> metadata) {
    return new TaxonomyInfo(
        TaxonomyPattern.PATTERN_B,
        individuals,
        null,
        false,
        null,
        propertyName,
        metadata,
        List.of()
    );
  }

  /**
   * Creates TaxonomyInfo for Pattern B (typed individuals with property graphs).
   */
  public static TaxonomyInfo patternB(
      String propertyName,
      List<OWLNamedIndividual> individuals,
      Map<String, IndividualMetadata> metadata,
      List<IndividualGraph> individualGraphs) {
    return new TaxonomyInfo(
        TaxonomyPattern.PATTERN_B,
        individuals,
        null,
        false,
        null,
        propertyName,
        metadata,
        individualGraphs
    );
  }

  /**
   * Creates TaxonomyInfo for Pattern C (class-based taxonomy).
   */
  public static TaxonomyInfo patternC(
      String propertyName,
      OWLClass targetClass,
      List<OWLNamedIndividual> individuals,
      boolean hasHierarchy) {
    return new TaxonomyInfo(
        TaxonomyPattern.PATTERN_C,
        individuals,
        targetClass,
        hasHierarchy,
        null,
        propertyName,
        Map.of(),
        List.of()
    );
  }

  /**
   * Creates TaxonomyInfo for Pattern D (SKOS taxonomy).
   */
  public static TaxonomyInfo patternD(
      String propertyName,
      OWLClass targetClass,
      List<OWLNamedIndividual> individuals,
      OWLIndividual conceptScheme) {
    return new TaxonomyInfo(
        TaxonomyPattern.PATTERN_D,
        individuals,
        targetClass,
        true, // SKOS hierarchies use skos:broader/narrower
        conceptScheme,
        propertyName,
        Map.of(),
        List.of()
    );
  }

  /**
   * Creates TaxonomyInfo indicating no taxonomy pattern was detected.
   */
  public static TaxonomyInfo none(String propertyName) {
    return new TaxonomyInfo(
        TaxonomyPattern.NONE,
        List.of(),
        null,
        false,
        null,
        propertyName,
        Map.of(),
        List.of()
    );
  }

  /**
   * @return true if a valid taxonomy pattern was detected
   */
  public boolean isTaxonomy() {
    return pattern != TaxonomyPattern.NONE;
  }

  /**
   * @return the target class if present
   */
  public Optional<OWLClass> getTargetClass() {
    return Optional.ofNullable(targetClass);
  }

  /**
   * @return the concept scheme if present (Pattern D)
   */
  public Optional<OWLIndividual> getConceptScheme() {
    return Optional.ofNullable(conceptScheme);
  }
}

